import { describe, it, expect } from 'vitest';
import {
  validateUserExists,
  validateEmailNotTaken,
  validateEmailAvailableForUpdate,
} from '../../src/validators/user.validator.js';
import type { User } from '../../src/models/user.js';

function makeUser(overrides: Partial<User> = {}): User {
  return {
    id: 'user-0001',
    name: 'Alice',
    email: 'alice@example.com',
    role: 'member',
    createdAt: new Date(),
    updatedAt: new Date(),
    ...overrides,
  };
}

describe('User Validators', () => {
  describe('validateUserExists', () => {
    it('should not throw when user exists', () => {
      const user = makeUser();
      expect(() => validateUserExists('user-0001', user)).not.toThrow();
    });

    it('should throw when user is undefined', () => {
      expect(() => validateUserExists('user-9999', undefined)).toThrow(
        'User not found: user-9999',
      );
    });

    it('should include the ID in the error message', () => {
      expect(() => validateUserExists('abc-123', undefined)).toThrow('abc-123');
    });
  });

  describe('validateEmailNotTaken', () => {
    it('should not throw when no existing user has the email', () => {
      expect(() => validateEmailNotTaken('new@example.com', undefined)).not.toThrow();
    });

    it('should throw when email is already taken', () => {
      const existing = makeUser({ email: 'taken@example.com' });
      expect(() => validateEmailNotTaken('taken@example.com', existing)).toThrow(
        'User with email taken@example.com already exists',
      );
    });

    it('should include the email in the error message', () => {
      const existing = makeUser({ email: 'foo@bar.com' });
      expect(() => validateEmailNotTaken('foo@bar.com', existing)).toThrow(
        'foo@bar.com',
      );
    });
  });

  describe('validateEmailAvailableForUpdate', () => {
    it('should not throw when email is not being changed', () => {
      expect(() =>
        validateEmailAvailableForUpdate(undefined, 'current@example.com', undefined),
      ).not.toThrow();
    });

    it('should not throw when new email is same as current', () => {
      expect(() =>
        validateEmailAvailableForUpdate(
          'current@example.com',
          'current@example.com',
          undefined,
        ),
      ).not.toThrow();
    });

    it('should not throw when new email is different and not taken', () => {
      expect(() =>
        validateEmailAvailableForUpdate(
          'new@example.com',
          'current@example.com',
          undefined,
        ),
      ).not.toThrow();
    });

    it('should throw when new email is different and already taken', () => {
      const existing = makeUser({ email: 'taken@example.com' });
      expect(() =>
        validateEmailAvailableForUpdate(
          'taken@example.com',
          'current@example.com',
          existing,
        ),
      ).toThrow('Email taken@example.com is already in use');
    });

    it('should not throw when email equals current even if existingUser is provided', () => {
      const existing = makeUser({ email: 'same@example.com' });
      expect(() =>
        validateEmailAvailableForUpdate(
          'same@example.com',
          'same@example.com',
          existing,
        ),
      ).not.toThrow();
    });
  });
});

import { describe, it, expect } from 'vitest';
import {
  validateOrderExists,
  validateOrderHasItems,
  isValidStatusTransition,
  validateStatusTransition,
} from '../../src/validators/order.validator.js';
import type { Order, OrderItem, OrderStatus } from '../../src/models/order.js';

function makeOrder(overrides: Partial<Order> = {}): Order {
  return {
    id: 'order-0001',
    userId: 'user-0001',
    items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
    total: 10,
    status: 'pending',
    createdAt: new Date(),
    updatedAt: new Date(),
    ...overrides,
  };
}

describe('Order Validators', () => {
  describe('validateOrderExists', () => {
    it('should not throw when order exists', () => {
      const order = makeOrder();
      expect(() => validateOrderExists('order-0001', order)).not.toThrow();
    });

    it('should throw when order is undefined', () => {
      expect(() => validateOrderExists('order-9999', undefined)).toThrow(
        'Order not found: order-9999',
      );
    });

    it('should include the ID in the error message', () => {
      expect(() => validateOrderExists('xyz-789', undefined)).toThrow('xyz-789');
    });
  });

  describe('validateOrderHasItems', () => {
    it('should not throw when items array has elements', () => {
      const items: OrderItem[] = [
        { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
      ];
      expect(() => validateOrderHasItems(items)).not.toThrow();
    });

    it('should not throw when items array has multiple elements', () => {
      const items: OrderItem[] = [
        { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
        { productId: 'p2', name: 'Gadget', quantity: 2, unitPrice: 20 },
      ];
      expect(() => validateOrderHasItems(items)).not.toThrow();
    });

    it('should throw when items array is empty', () => {
      expect(() => validateOrderHasItems([])).toThrow(
        'Order must have at least one item',
      );
    });
  });

  describe('isValidStatusTransition', () => {
    it('should allow pending -> confirmed', () => {
      expect(isValidStatusTransition('pending', 'confirmed')).toBe(true);
    });

    it('should allow pending -> cancelled', () => {
      expect(isValidStatusTransition('pending', 'cancelled')).toBe(true);
    });

    it('should allow confirmed -> shipped', () => {
      expect(isValidStatusTransition('confirmed', 'shipped')).toBe(true);
    });

    it('should allow confirmed -> cancelled', () => {
      expect(isValidStatusTransition('confirmed', 'cancelled')).toBe(true);
    });

    it('should allow shipped -> delivered', () => {
      expect(isValidStatusTransition('shipped', 'delivered')).toBe(true);
    });

    it('should reject pending -> delivered', () => {
      expect(isValidStatusTransition('pending', 'delivered')).toBe(false);
    });

    it('should reject pending -> shipped', () => {
      expect(isValidStatusTransition('pending', 'shipped')).toBe(false);
    });

    it('should reject delivered -> any transition (terminal state)', () => {
      const statuses: OrderStatus[] = ['pending', 'confirmed', 'shipped', 'delivered', 'cancelled'];
      for (const to of statuses) {
        expect(isValidStatusTransition('delivered', to)).toBe(false);
      }
    });

    it('should reject cancelled -> any transition (terminal state)', () => {
      const statuses: OrderStatus[] = ['pending', 'confirmed', 'shipped', 'delivered', 'cancelled'];
      for (const to of statuses) {
        expect(isValidStatusTransition('cancelled', to)).toBe(false);
      }
    });

    it('should reject shipped -> confirmed (backwards transition)', () => {
      expect(isValidStatusTransition('shipped', 'confirmed')).toBe(false);
    });
  });

  describe('validateStatusTransition', () => {
    it('should not throw for valid transition', () => {
      expect(() => validateStatusTransition('pending', 'confirmed')).not.toThrow();
    });

    it('should throw for invalid transition', () => {
      expect(() => validateStatusTransition('pending', 'delivered')).toThrow(
        'Invalid status transition: pending -> delivered',
      );
    });

    it('should throw for terminal state transition', () => {
      expect(() => validateStatusTransition('cancelled', 'confirmed')).toThrow(
        'Invalid status transition: cancelled -> confirmed',
      );
    });

    it('should include both statuses in the error message', () => {
      expect(() => validateStatusTransition('delivered', 'shipped')).toThrow(
        'delivered -> shipped',
      );
    });
  });
});

import { describe, it, expect } from 'vitest';
import {
  validatePreferencesNotExist,
  validatePreferencesExist,
} from '../../src/validators/preferences.validator.js';
import type { UserNotificationPreferences } from '../../src/models/user-preferences.js';

function makePreferences(
  overrides: Partial<UserNotificationPreferences> = {},
): UserNotificationPreferences {
  return {
    id: 'pref-0001',
    userId: 'user-0001',
    email: {
      enabled: true,
      frequency: 'immediate',
      categoryPreferences: [],
    },
    createdAt: new Date(),
    updatedAt: new Date(),
    ...overrides,
  };
}

describe('Preferences Validators', () => {
  describe('validatePreferencesNotExist', () => {
    it('should not throw when no preferences exist', () => {
      expect(() =>
        validatePreferencesNotExist('user-0001', undefined),
      ).not.toThrow();
    });

    it('should throw when preferences already exist', () => {
      const existing = makePreferences();
      expect(() =>
        validatePreferencesNotExist('user-0001', existing),
      ).toThrow('Preferences already exist for user: user-0001');
    });

    it('should include the userId in the error message', () => {
      const existing = makePreferences({ userId: 'user-42' });
      expect(() =>
        validatePreferencesNotExist('user-42', existing),
      ).toThrow('user-42');
    });
  });

  describe('validatePreferencesExist', () => {
    it('should not throw when preferences exist', () => {
      const existing = makePreferences();
      expect(() =>
        validatePreferencesExist('user-0001', existing),
      ).not.toThrow();
    });

    it('should throw when preferences are undefined', () => {
      expect(() =>
        validatePreferencesExist('user-9999', undefined),
      ).toThrow('No preferences found for user: user-9999');
    });

    it('should include the userId in the error message', () => {
      expect(() =>
        validatePreferencesExist('user-abc', undefined),
      ).toThrow('user-abc');
    });

    it('should act as type assertion (asserts existing is UserNotificationPreferences)', () => {
      const existing: UserNotificationPreferences | undefined = makePreferences();
      // After calling validatePreferencesExist, existing should be narrowed to UserNotificationPreferences
      validatePreferencesExist('user-0001', existing);
      // If TypeScript compiles this, the assertion type works correctly
      expect(existing.id).toBe('pref-0001');
      expect(existing.userId).toBe('user-0001');
    });
  });
});
